import Foundation

// The reference "empty project" .mt buffer, base64-encoded — a verbatim copy of
// LATEST_PROJECT_TEMPLATE from tracker-lib src/data/project.ts. The project
// writer starts from this buffer and patches fixed offsets (header, playlist,
// tempo, names, delay/reverb), so every byte the codec doesn't touch matches
// real hardware output.
enum PolyendProjectTemplate {
    static let base64 =
        ""

    /// The decoded reference buffer (a fresh copy each call so the writer can mutate it).
    static func buffer() -> [UInt8] {
        guard let data = Data(base64Encoded: base64) else { return [] }
        return [UInt8](data)
    }
}
